import { readFileSync } from 'node:fs';
const recovery=readFileSync('packages/agent-core/src/ultrawork/recovery-injectors.ts','utf8');
const cos=readFileSync('packages/agent-core/src/agent/context-os/index.ts','utf8');
const fails=[];
if (!recovery.includes('injectUltraworkPostSwarmContinuation')) fails.push('post-swarm-fn');
if (!recovery.includes('injectUltraworkPostCompactionContinuation')) fails.push('post-compact-fn');
const hits=recovery.split('formatContinuityOperatorNote(agent.contextOS.health())').length-1;
if (hits < 2) fails.push('continuity-both-paths');
if (!cos.includes('export function formatContinuityOperatorNote')) fails.push('continuity-export');
if (!recovery.includes('Resume node:')) fails.push('resume-node');
if (!recovery.includes('Next actions:')) fails.push('next-actions');
if (fails.length){console.error(fails.join(',')); process.exit(1);} console.log('ultrawork-recovery-continuity-ok');
